-- Generated from supabase/seed/maison_sample_dataset/*.csv
-- Seeds categories, products, orders, order_items in UUID-compatible format.

BEGIN;

CREATE OR REPLACE FUNCTION public.text_to_uuid(input text)
RETURNS uuid
LANGUAGE sql
IMMUTABLE
AS $$
  SELECT (substr(md5(input),1,8)||'-'||substr(md5(input),9,4)||'-'||substr(md5(input),13,4)||'-'||substr(md5(input),17,4)||'-'||substr(md5(input),21,12))::uuid;
$$;

